+    case vmIntrinsics::_binarySearchLong:
+      min_length = BSEARCH_LONG_STUB_MIN;
+      break;
+    case vmIntrinsics::_binarySearchShort:
+      min_length = BSEARCH_SHORT_STUB_MIN;
